import java.io.*;
import java.util.*;
public class Main{
    public static void main(String[] args) throws Exception{
        FastScanner fs=new FastScanner(System.in);
        int T=fs.nextInt();
        StringBuilder sb=new StringBuilder();
        while(T-- > 0){
            int N=fs.nextInt();
            long[] a=new long[N];
            long[] b=new long[N];
            for(int i=0;i<N;i++){
                a[i]=fs.nextLong();
                b[i]=a[i];
            }
            Arrays.sort(b);
            int j=0;
            long[] rem=new long[N];
            int rlen=0;
            for(int i=0;i<N;i++){
                if(j<N && a[i]==b[j]) j++;
                else rem[rlen++]=a[i];
            }
            boolean ok=true;
            if(j+rlen!=N) ok=false;
            else{
                for(int k=0;k<rlen;k++) if(rem[k]!=b[j+k]){ok=false;break;}
            }
            sb.append(ok?"YES":"NO").append('\n');
        }
        System.out.print(sb.toString());
    }
    static class FastScanner{
        private final InputStream in;
        private final byte[] buffer=new byte[1<<16];
        private int ptr=0, len=0;
        FastScanner(InputStream in){this.in=in;}
        private int readByte() throws IOException{
            if(ptr>=len){len=in.read(buffer);ptr=0;if(len<=0) return -1;}
            return buffer[ptr++];
        }
        long nextLong() throws IOException{int c; do{c=readByte();}while(c<=32 && c!=-1); boolean neg=false; if(c=='-'){neg=true;c=readByte();}
            long val=0; while(c>32 && c!=-1){val=val*10+(c-'0');c=readByte();}
            return neg?-val:val;}
        int nextInt() throws IOException{return (int)nextLong();}
    }
}

