const fs=require('fs');
const input=fs.readFileSync(0,'utf-8').trim().split(/\s+/).map(Number);
let idx=0;
const T=input[idx++];
let out=[];
for(let tc=0;tc<T;tc++){
  const N=input[idx++];
  const a=input.slice(idx, idx+N); idx+=N;
  const b=[...a].sort((x,y)=>x-y);
  let j=0; const rem=[];
  for(let x of a){
    if(j<N && x===b[j]) j++; else rem.push(x);
  }
  const ok = (j+rem.length===N) && rem.every((v,i)=>v===b[j+i]);
  out.push(ok?'YES':'NO');
}
console.log(out.join('\n'));
